     1→#!/usr/bin/env bun
     2→/**
     3→ * PAI Installation Wizard
     4→ *
     5→ * Interactive setup that walks you through personalizing your PAI:
     6→ * - Sets your name and timezone
     7→ * - Names your AI assistant
     8→ * - Configures voice settings
     9→ * - Fixes permissions and starts services
    10→ *
    11→ * Usage:
    12→ *   bun run INSTALL.ts    # Run the interactive wizard
    13→ */
    14→
    15→import { existsSync, mkdirSync, readFileSync, writeFileSync, readdirSync } from 'fs';
    16→import { join } from 'path';
    17→import { homedir, userInfo } from 'os';
    18→import { execSync, spawn } from 'child_process';
    19→import * as readline from 'readline';
    20→
    21→// ANSI colors
    22→const c = {
    23→  reset: '\x1b[0m',
    24→  bold: '\x1b[1m',
    25→  blue: '\x1b[38;2;59;130;246m',
    26→  green: '\x1b[38;2;34;197;94m',
    27→  yellow: '\x1b[38;2;234;179;8m',
    28→  red: '\x1b[38;2;239;68;68m',
    29→  cyan: '\x1b[38;2;6;182;212m',
    30→  gray: '\x1b[38;2;100;116;139m',
    31→};
    32→
    33→// Paths
    34→const HOME = homedir();
    35→const CLAUDE_DIR = join(HOME, '.claude');
    36→const ZSHRC = join(HOME, '.zshrc');
    37→const VOICE_SERVER_DIR = join(CLAUDE_DIR, 'VoiceServer');
    38→const VOICE_SERVER_PORT = 8888;
    39→
    40→// Default voice IDs - ElevenLabs pre-made voices (work with any API key)
    41→// Reference: https://elevenlabs-sdk.mintlify.app/voices/premade-voices
    42→const DEFAULT_VOICES = {
    43→  male: 'pNInz6obpgDQGcFmaJgB',      // Adam (male)
    44→  female: '21m00Tcm4TlvDq8ikWAM',    // Rachel (female)
    45→  neutral: 'ErXwobaYiN019PkySvjV',   // Antoni (versatile male)
    46→};
    47→
    48→interface InstallConfig {
    49→  PRINCIPAL_NAME: string;
    50→  TIMEZONE?: string;
    51→  AI_NAME?: string;
    52→  CATCHPHRASE?: string;
    53→  VOICE_TYPE?: 'male' | 'female' | 'neutral';
    54→  ELEVENLABS_KEY?: string;
    55→  CUSTOM_VOICE_ID?: string;
    56→  PROJECTS_DIR?: string;
    57→}
    58→
    59→// ============================================================================
    60→// UTILITY FUNCTIONS
    61→// ============================================================================
    62→
    63→function print(msg: string) { console.log(msg); }
    64→function printSuccess(msg: string) { print(`  ${c.green}✓${c.reset} ${msg}`); }
    65→function printWarning(msg: string) { print(`  ${c.yellow}!${c.reset} ${msg}`); }
    66→function printError(msg: string) { print(`  ${c.red}✗${c.reset} ${msg}`); }
    67→function printInfo(msg: string) { print(`  ${c.gray}→${c.reset} ${msg}`); }
    68→
    69→function createReadline(): readline.Interface {
    70→  return readline.createInterface({
    71→    input: process.stdin,
    72→    output: process.stdout,
    73→  });
    74→}
    75→
    76→async function prompt(question: string, defaultValue?: string): Promise<string> {
    77→  const displayDefault = defaultValue ? ` ${c.gray}[${defaultValue}]${c.reset}` : '';
    78→  const rl = createReadline();
    79→
    80→  return new Promise((resolve) => {
    81→    rl.question(`  ${question}${displayDefault}: `, (answer) => {
    82→      rl.close();
    83→      resolve(answer.trim() || defaultValue || '');
    84→    });
    85→  });
    86→}
    87→
    88→async function promptChoice(question: string, choices: string[], defaultIdx = 0): Promise<number> {
    89→  print(`  ${question}`);
    90→  choices.forEach((choice, i) => {
    91→    const marker = i === defaultIdx ? `${c.cyan}→${c.reset}` : ' ';
    92→    print(`    ${marker} ${i + 1}. ${choice}`);
    93→  });
    94→
    95→  const rl = createReadline();
    96→  return new Promise((resolve) => {
    97→    rl.question(`  ${c.gray}Enter 1-${choices.length} [${defaultIdx + 1}]:${c.reset} `, (answer) => {
    98→      rl.close();
    99→      const num = parseInt(answer.trim()) || (defaultIdx + 1);
   100→      resolve(Math.max(0, Math.min(choices.length - 1, num - 1)));
   101→    });
   102→  });
   103→}
   104→
   105→// ============================================================================
   106→// PERMISSIONS (chmod → chown → chmod)
   107→// ============================================================================
   108→
   109→function fixPermissions(targetDir: string): void {
   110→  const info = userInfo();
   111→
   112→  print('');
   113→  print(`${c.bold}Fixing permissions for ${info.username}${c.reset}`);
   114→  print(`${c.gray}─────────────────────────────────────────────────${c.reset}`);
   115→
   116→  try {
   117→    // Step 1: chmod first - make files accessible
   118→    execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
   119→    printSuccess('Step 1: chmod -R 755 (make accessible)');
   120→
   121→    // Step 2: chown - change ownership to current user
   122→    execSync(`chown -R ${info.uid}:${info.gid} "${targetDir}"`, { stdio: 'pipe' });
   123→    printSuccess(`Step 2: chown -R to ${info.username}`);
   124→
   125→    // Step 3: chmod again - set final permissions
   126→    execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
   127→    printSuccess('Step 3: chmod -R 755 (final permissions)');
   128→
   129→    // Make scripts executable
   130→    for (const pattern of ['*.ts', '*.sh', '*.hook.ts']) {
   131→      try {
   132→        execSync(`find "${targetDir}" -name "${pattern}" -exec chmod 755 {} \\;`, { stdio: 'pipe' });
   133→      } catch (e) { /* ignore */ }
   134→    }
   135→    printSuccess('Set executable permissions on scripts');
   136→
   137→  } catch (err: any) {
   138→    printError(`Permission fix failed: ${err.message}`);
   139→    print(`${c.yellow}Run: sudo chown -R $(whoami) ${targetDir}${c.reset}`);
   140→  }
   141→}
   142→
   143→// ============================================================================
   144→// VOICE SERVER MANAGEMENT
   145→// ============================================================================
   146→
   147→function findRunningVoiceServers(): number[] {
   148→  try {
   149→    const result = execSync(`lsof -ti:${VOICE_SERVER_PORT}`, { encoding: 'utf-8', stdio: ['pipe', 'pipe', 'pipe'] });
   150→    return result.trim().split('\n').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
   151→  } catch (e) {
   152→    return [];
   153→  }
   154→}
   155→
   156→function killVoiceServers(): void {
   157→  const pids = findRunningVoiceServers();
   158→  if (pids.length > 0) {
   159→    printInfo(`Killing ${pids.length} existing voice server(s)`);
   160→    for (const pid of pids) {
   161→      try {
   162→        execSync(`kill -9 ${pid}`, { stdio: 'pipe' });
   163→        printSuccess(`Killed process ${pid}`);
   164→      } catch (e) { /* ignore */ }
   165→    }
   166→  }
   167→}
   168→
   169→async function startVoiceServer(): Promise<boolean> {
   170→  const startScript = join(VOICE_SERVER_DIR, 'start.sh');
   171→  if (!existsSync(startScript)) {
   172→    printWarning('Voice server start script not found');
   173→    return false;
   174→  }
   175→
   176→  killVoiceServers();
   177→
   178→  try {
   179→    const child = spawn('bash', [startScript], {
   180→      detached: true,
   181→      stdio: 'ignore',
   182→      cwd: VOICE_SERVER_DIR,
   183→    });
   184→    child.unref();
   185→
   186→    await new Promise(resolve => setTimeout(resolve, 2000));
   187→
   188→    if (findRunningVoiceServers().length > 0) {
   189→      printSuccess('Voice server started');
   190→      return true;
   191→    } else {
   192→      printWarning('Voice server may not have started');
   193→      return false;
   194→    }
   195→  } catch (err: any) {
   196→    printError(`Failed to start voice server: ${err.message}`);
   197→    return false;
   198→  }
   199→}
   200→
   201→async function testVoice(message: string): Promise<boolean> {
   202→  try {
   203→    const response = await fetch(`http://localhost:${VOICE_SERVER_PORT}/notify`, {
   204→      method: 'POST',
   205→      headers: { 'Content-Type': 'application/json' },
   206→      body: JSON.stringify({ message }),
   207→    });
   208→    return response.ok;
   209→  } catch (e) {
   210→    return false;
   211→  }
   212→}
