   214→// ============================================================================
   215→// BUN INSTALLATION
   216→// ============================================================================
   217→
   218→function installBun(): void {
   219→  print('');
   220→  print(`${c.bold}Checking Bun Runtime${c.reset}`);
   221→  print(`${c.gray}─────────────────────────────────────────────────${c.reset}`);
   222→
   223→  try {
   224→    // Check if bun is installed
   225→    const bunVersion = execSync('bun --version 2>/dev/null', { encoding: 'utf-8' }).trim();
   226→    printSuccess(`Bun ${bunVersion} found`);
   227→
   228→    // Upgrade to latest
   229→    printInfo('Upgrading Bun to latest version...');
   230→    try {
   231→      execSync('bun upgrade', { stdio: 'inherit' });
   232→      const newVersion = execSync('bun --version', { encoding: 'utf-8' }).trim();
   233→      printSuccess(`Bun upgraded to ${newVersion}`);
   234→    } catch {
   235→      printWarning('Could not upgrade Bun (may already be latest)');
   236→    }
   237→  } catch {
   238→    // Bun not installed, install it
   239→    printInfo('Bun not found, installing...');
   240→    try {
   241→      execSync('curl -fsSL https://bun.sh/install | bash', {
   242→        stdio: 'inherit',
   243→        shell: '/bin/bash'
   244→      });
   245→
   246→      // Source the new bun path
   247→      const bunPath = join(HOME, '.bun/bin');
   248→      process.env.PATH = `${bunPath}:${process.env.PATH}`;
   249→
   250→      const newVersion = execSync('bun --version', { encoding: 'utf-8' }).trim();
   251→      printSuccess(`Bun ${newVersion} installed`);
   252→      printInfo('You may need to restart your terminal for bun to be in PATH');
   253→    } catch (err: any) {
   254→      printError(`Failed to install Bun: ${err.message}`);
   255→      printInfo('Please install manually: curl -fsSL https://bun.sh/install | bash');
   256→    }
   257→  }
   258→}
   259→
   260→// ============================================================================
   261→// ZSH ALIAS
   262→// ============================================================================
   263→
   264→function setupZshAlias(): void {
   265→  const aliasLine = `alias pai='bun ~/.claude/skills/PAI/Tools/pai.ts'`;
   266→  const marker = '# PAI alias';
   267→
   268→  try {
   269→    let content = existsSync(ZSHRC) ? readFileSync(ZSHRC, 'utf-8') : '';
   270→
   271→    if (content.includes('alias pai=')) {
   272→      // Update existing
   273→      content = content.replace(/alias pai=.*/, aliasLine);
   274→      writeFileSync(ZSHRC, content);
   275→      printSuccess('Updated PAI alias in .zshrc');
   276→    } else {
   277→      // Add new
   278→      writeFileSync(ZSHRC, content + `\n${marker}\n${aliasLine}\n`);
   279→      printSuccess('Added PAI alias to .zshrc');
   280→    }
   281→    printInfo('Run "source ~/.zshrc" to enable "pai" command');
   282→  } catch (err: any) {
   283→    printWarning(`Could not update .zshrc: ${err.message}`);
   284→  }
   285→}
