     1→/**
     2→ * recovery-types.ts - Type definitions for the recovery journal system
     3→ */
     4→
     5→export interface RecoveryPoint {
     6→  id: string;                    // UUID for this recovery point
     7→  timestamp: string;             // ISO timestamp
     8→  timestamp_pst: string;         // PST for display
     9→  session_id: string;            // Claude session that triggered
    10→  command: string;               // Original command (truncated)
    11→  command_type: DestructiveType; // Classification
    12→  affected_paths: string[];      // Files/dirs that will be modified
    13→  snapshot_path?: string;        // Path to snapshot archive
    14→  status: 'pending' | 'created' | 'restored' | 'expired';
    15→  file_count?: number;           // Number of files in snapshot
    16→  snapshot_size?: number;        // Size in bytes
    17→}
    18→
    19→export type DestructiveType =
    20→  | 'file_delete'      // rm, unlink
    21→  | 'file_move'        // mv (source files disappear)
    22→  | 'git_reset'        // git reset --hard, git checkout --
    23→  | 'git_clean'        // git clean -fd
    24→  | 'directory_delete' // rm -r, rmdir
    25→  | 'overwrite'        // > redirect, cp that overwrites
    26→  | 'bulk_modify';     // sed -i, find -exec
    27→
    28→export interface DestructivePattern {
    29→  pattern: RegExp;
    30→  type: DestructiveType;
    31→  extractPaths: (command: string) => string[];
    32→}
    33→
    34→export interface RecoveryIndex {
    35→  last_updated: string;
    36→  total_points: number;
    37→  points: RecoveryPointSummary[];
    38→}
    39→
    40→export interface RecoveryPointSummary {
    41→  id: string;
    42→  timestamp: string;
    43→  command_type: DestructiveType;
    44→  affected_paths: string[];
    45→  snapshot_path?: string;
    46→  status: string;
    47→  file_count?: number;
    48→}
    49→
    50→// Safe paths that don't need journaling (within .claude ecosystem)
    51→const PAI_DIR = process.env.PAI_DIR || `${process.env.HOME}/.claude`;
    52→export const SAFE_PATH_PREFIXES = [
    53→  `${PAI_DIR}/MEMORY/`,  // All MEMORY output is safe (sessions, learnings, raw-outputs, etc.)
    54→  `${PAI_DIR}/Scratchpad/`,
    55→  `${PAI_DIR}/Tmp/`,
    56→  `${PAI_DIR}/Debug/`,
    57→  `${PAI_DIR}/SessionEnv/`,
    58→  `${PAI_DIR}/Todos/`,
    59→  '/tmp/',
    60→  '/var/tmp/',
    61→];
    62→
    63→// Skip journaling for these output-only operations
    64→export const SKIP_COMMAND_PATTERNS = [
    65→  /^\s*ls\b/,
    66→  /^\s*cat\b/,
    67→  /^\s*head\b/,
    68→  /^\s*tail\b/,
    69→  /^\s*echo\s+[^>]/,  // echo without redirect
    70→  /^\s*pwd\b/,
    71→  /^\s*which\b/,
    72→  /^\s*git\s+(status|log|diff|show|branch|remote)\b/,
    73→  /^\s*find\b[^|]*$/,  // find without pipe
    74→  /^\s*grep\b/,
    75→  /^\s*rg\b/,
    76→];
    77→
    78→// Patterns that indicate destructive operations requiring journaling
    79→export const DESTRUCTIVE_PATTERNS: DestructivePattern[] = [
    80→  {
    81→    pattern: /\brm\s+(?:-[rfivd]+\s+)*([^\|;&]+)/i,
    82→    type: 'file_delete',
    83→    extractPaths: extractRmPaths
    84→  },
    85→  {
    86→    pattern: /\bmv\s+([^\|;&]+)/i,
    87→    type: 'file_move',
    88→    extractPaths: extractMvSourcePaths
    89→  },
    90→  {
    91→    pattern: /\bgit\s+reset\s+--hard/i,
    92→    type: 'git_reset',
    93→    extractPaths: () => ['.'] // Current git repo
    94→  },
    95→  {
    96→    pattern: /\bgit\s+checkout\s+--\s+([^\|;&]+)/i,
    97→    type: 'git_reset',
    98→    extractPaths: (cmd) => {
    99→      const match = cmd.match(/git\s+checkout\s+--\s+(.+)/i);
   100→      return match ? match[1].trim().split(/\s+/) : ['.'];
   101→    }
   102→  },
   103→  {
   104→    pattern: /\bgit\s+clean\s+-[fd]+/i,
   105→    type: 'git_clean',
   106→    extractPaths: () => ['.'] // Current git repo
   107→  },
   108→];
   109→
   110→/**
   111→ * Extract paths from rm command
   112→ */
   113→function extractRmPaths(command: string): string[] {
   114→  // Remove the 'rm' and flags, get the paths
   115→  const withoutRm = command.replace(/^\s*rm\s+/, '');
   116→  const withoutFlags = withoutRm.replace(/^(-[rfivd]+\s+)+/, '');
   117→
   118→  // Split on whitespace, filter empty
   119→  return withoutFlags
   120→    .split(/\s+/)
   121→    .filter(p => p && !p.startsWith('-'))
   122→    .map(p => p.replace(/['"`]/g, '')); // Remove quotes
   123→}
   124→
   125→/**
   126→ * Extract source paths from mv command (files being moved/renamed)
   127→ */
   128→function extractMvSourcePaths(command: string): string[] {
   129→  const withoutMv = command.replace(/^\s*mv\s+/, '');
   130→  const withoutFlags = withoutMv.replace(/^(-[fivn]+\s+)+/, '');
   131→
   132→  const parts = withoutFlags.split(/\s+/).filter(p => p && !p.startsWith('-'));
   133→
   134→  // Last part is destination, everything else is source
   135→  if (parts.length >= 2) {
   136→    return parts.slice(0, -1).map(p => p.replace(/['"`]/g, ''));
   137→  }
   138→
   139→  return parts.map(p => p.replace(/['"`]/g, ''));
   140→}
