    43→];
    44→
    45→// Garbage patterns for ALL messages - these are always conversational filler
    46→const ALWAYS_GARBAGE_PATTERNS = [
    47→  /appreciate/i,
    48→  /thank/i,
    49→  /welcome/i,
    50→  /help(ing)? you/i,   // "help you" or "Helping you"
    51→  /assist(ing)? you/i, // "assist you" or "Assisting you"
    52→  /reaching out/i,
    53→  /happy to/i,
    54→  /let me know/i,
    55→  /feel free/i,
    56→];
    57→
    58→// Conversational starters that aren't factual summaries
    59→const CONVERSATIONAL_STARTERS = [
    60→  /^I'm /i,
    61→  /^I am /i,
    62→  /^Sure[,.]?/i,
    63→  /^OK[,.]?/i,
    64→  /^Got it[,.]?/i,
    65→  /^Done\.?$/i,
    66→  /^Yes[,.]?/i,
    67→  /^No[,.]?/i,
    68→  /^Okay[,.]?/i,
    69→  /^Alright[,.]?/i,
    70→];
    71→
    72→// Explicit blocklist for single-word garbage
    73→const SINGLE_WORD_BLOCKLIST = [
    74→  'ready', 'done', 'ok', 'okay', 'yes', 'no', 'sure', 'prefix',
    75→  'hello', 'hi', 'hey', 'thanks', 'working', 'processing'
    76→];
    77→
    78→/**
    79→ * Check if a voice completion is valid
    80→ * Voice completions should be factual summaries, not conversational fluff
    81→ */
    82→export function isValidVoiceCompletion(text: string): boolean {
    83→  if (!text || text.length < 3) return false;
    84→
    85→  // Reject single words (almost always garbage)
    86→  const wordCount = text.trim().split(/\s+/).length;
    87→  if (wordCount === 1) {
    88→    const lowerText = text.toLowerCase().replace(/[^a-z]/g, '');
    89→    if (SINGLE_WORD_BLOCKLIST.includes(lowerText)) return false;
    90→    // Single words under 10 chars are suspicious
    91→    if (lowerText.length < 10) return false;
    92→  }
    93→
    94→  // Reject very short messages (less than 10 chars usually garbage)
    95→  if (text.length < 10) return false;
    96→
    97→  // Always reject these conversational filler patterns
    98→  for (const pattern of ALWAYS_GARBAGE_PATTERNS) {
    99→    if (pattern.test(text)) return false;
   100→  }
   101→
   102→  // Only apply short-message garbage patterns to messages < 40 chars
   103→  // Longer messages can legitimately contain "ready", "hello" etc. in context
   104→  if (text.length < 40) {
   105→    for (const pattern of SHORT_MESSAGE_GARBAGE) {
   106→      if (pattern.test(text)) return false;
   107→    }
   108→  }
   109→
   110→  // Reject conversational starters
   111→  for (const pattern of CONVERSATIONAL_STARTERS) {
   112→    if (pattern.test(text)) return false;
   113→  }
   114→
   115→  return true;
   116→}
   117→
   118→// Words that indicate an incomplete sentence when they appear at the end
   119→// This is a WHITELIST approach: we define what "incomplete" looks like
   120→// instead of trying to blacklist every possible fragment pattern
   121→const INCOMPLETE_ENDINGS = [
   122→  'the', 'a', 'an',           // articles
   123→  'to', 'for', 'with', 'of',  // prepositions
   124→  'in', 'on', 'at', 'by',     // more prepositions
   125→  'from', 'into', 'about',    // more prepositions
   126→  'and', 'or', 'but',         // conjunctions
   127→  'that', 'which',            // relative pronouns
   128→];
   129→
   130→// Prepositions that when followed by a single word make incomplete phrases
   131→// e.g., "for root" (root what?), "to fix" (to fix what?)
   132→const PREPOSITIONS = ['to', 'for', 'with', 'from', 'into', 'about', 'of', 'on', 'at', 'by'];
   133→
   134→/**
   135→ * Check if a tab summary is valid - validates COMPLETE sentences.
   136→ *
   137→ * Requirements:
   138→ * - Must be 2-6 words (single words are usually garbage)
   139→ * - Must START with a gerund (-ing verb) - CRITICAL check
   140→ * - Must end with a period
   141→ * - No conversational garbage
   142→ * - No incomplete endings (dangling prepositions, articles)
   143→ */
   144→export function isValidTabSummary(text: string): boolean {
   145→  if (!text || text.length < 5) return false;
   146→
   147→  // Must end with a period
   148→  if (!text.endsWith('.')) return false;
   149→
   150→  // Remove the period for word analysis
   151→  const content = text.slice(0, -1).trim();
   152→  const words = content.split(/\s+/);
   153→
   154→  // Must be 2-6 words (single words are usually garbage like "Processing.")
   155→  if (words.length < 2 || words.length > 6) return false;
   156→
   157→  // CRITICAL: Must start with a gerund (-ing verb)
   158→  // This catches garbage like "Fiction Apps Monetization Optimized" where
   159→  // the model picked up content topics instead of summarizing the task
   160→  const firstWord = words[0].toLowerCase();
   161→  if (!firstWord.endsWith('ing')) {
   162→    return false;
   163→  }
   164→
   165→  // Reject conversational garbage patterns
   166→  for (const pattern of ALWAYS_GARBAGE_PATTERNS) {
   167→    if (pattern.test(text)) return false;
   168→  }
   169→
   170→  // Reject first-person pronouns
   171→  const lowerContent = content.toLowerCase();
   172→  if (/\bi\b/.test(lowerContent) || /\bme\b/.test(lowerContent) || /\bmy\b/.test(lowerContent)) {
   173→    return false;
   174→  }
   175→
   176→  // Check for incomplete endings (dangling prepositions, articles, conjunctions)
   177→  const lastWord = words[words.length - 1].toLowerCase().replace(/[^a-z]/g, '');
   178→  if (INCOMPLETE_ENDINGS.includes(lastWord)) {
   179→    return false;
   180→  }
   181→
   182→  // Check for dangling preposition phrases (e.g., "Fixing issue with" is incomplete)
   183→  if (words.length >= 2) {
   184→    const secondToLast = words[words.length - 2].toLowerCase().replace(/[^a-z]/g, '');
   185→    // If second-to-last is a preposition and last word is short, likely fragment
   186→    if (PREPOSITIONS.includes(secondToLast) && lastWord.length <= 4) {
   187→      return false;
   188→    }
   189→  }
   190→
   191→  return true;
   192→}
   193→
   194→/**
   195→ * Get fallback for voice line
   196→ * When no valid voice line exists, stay silent (empty string)
   197→ */
   198→export function getVoiceFallback(): string {
   199→  return '';
   200→}
   201→
   202→/**
   203→ * Get fallback for tab title based on lifecycle stage
   204→ * @param stage - 'start' for beginning work, 'end' for completion
   205→ * Short and non-generic
   206→ */
   207→export function getTabFallback(stage: 'start' | 'end' = 'start'): string {
   208→  // NOTE: Do NOT include state symbols (✓, ⚠, ⚙️) here - tab-state.ts adds those based on state
   209→  return stage === 'end' ? 'Done.' : 'Working.';
   210→}
