     1→#!/usr/bin/env bun
     2→/**
     3→ * RebuildSkill.ts - Auto-rebuild CORE SKILL.md from Components
     4→ *
     5→ * PURPOSE:
     6→ * Automatically rebuilds SKILL.md from Components/ after every response.
     7→ * Ensures SKILL.md stays current if components were edited during the session.
     8→ *
     9→ * TRIGGER: Stop event (via StopOrchestrator)
    10→ *
    11→ * BEHAVIOR:
    12→ * - Checks if any Component file is newer than SKILL.md
    13→ * - If yes, runs BuildSkill.ts to regenerate SKILL.md
    14→ * - Logs rebuild status to stderr
    15→ *
    16→ * DESIGN RATIONALE:
    17→ * - Rebuild on session END (not START) keeps LoadContext fast
    18→ * - Components are source of truth, SKILL.md is generated artifact
    19→ * - No manual `bun BuildSkill.ts` needed - happens automatically
    20→ */
    21→
    22→import { statSync, readdirSync } from 'fs';
    23→import { join } from 'path';
    24→import { spawnSync } from 'child_process';
    25→
    26→export async function handleRebuildSkill(): Promise<void> {
    27→  const CORE_DIR = join(process.env.HOME!, '.claude/skills/PAI');
    28→  const COMPONENTS_DIR = join(CORE_DIR, 'Components');
    29→  const SKILL_MD = join(CORE_DIR, 'SKILL.md');
    30→  const BUILD_SCRIPT = join(CORE_DIR, 'Tools/CreateDynamicCore.ts');
    31→
    32→  try {
    33→    // Check if SKILL.md exists
    34→    let skillStat;
    35→    try {
    36→      skillStat = statSync(SKILL_MD);
    37→    } catch {
    38→      // SKILL.md doesn't exist - rebuild needed
    39→      console.error('[RebuildSkill] SKILL.md missing - rebuilding');
    40→      rebuild(BUILD_SCRIPT);
    41→      return;
    42→    }
    43→
    44→    // Check if any component is newer than SKILL.md
    45→    const components = readdirSync(COMPONENTS_DIR).filter(f => f.endsWith('.md'));
    46→    const anyNewer = components.some(file => {
    47→      const componentPath = join(COMPONENTS_DIR, file);
    48→      const componentStat = statSync(componentPath);
    49→      return componentStat.mtimeMs > skillStat.mtimeMs;
    50→    });
    51→
    52→    if (anyNewer) {
    53→      console.error('[RebuildSkill] Components modified - rebuilding SKILL.md');
    54→      rebuild(BUILD_SCRIPT);
    55→    } else {
    56→      console.error('[RebuildSkill] SKILL.md is current - no rebuild needed');
    57→    }
    58→  } catch (error) {
    59→    console.error('[RebuildSkill] Error checking/rebuilding:', error);
    60→  }
    61→}
    62→
    63→function rebuild(buildScript: string): void {
    64→  const result = spawnSync('bun', [buildScript], {
    65→    cwd: join(process.env.HOME!, '.claude/skills/PAI'),
    66→    encoding: 'utf-8',
    67→  });
    68→
    69→  if (result.error) {
    70→    console.error('[RebuildSkill] Build failed:', result.error);
    71→  } else {
    72→    console.error('[RebuildSkill]', result.stdout?.trim() || 'Build completed');
    73→  }
    74→}
