     1→#!/usr/bin/env bun
     2→/**
     3→ * ISCValidator.ts - ISC File Validation Handler (Stop Event)
     4→ *
     5→ * PURPOSE:
     6→ * Validates that ISC.json was properly populated during algorithm execution.
     7→ * Checks for empty criteria arrays and stale THREAD.md phases.
     8→ *
     9→ * VALIDATION RULES:
    10→ * 1. ISC.json criteria array must be non-empty after OBSERVE
    11→ * 2. ISC.json must have been modified since session start
    12→ * 3. THREAD.md should not have _Pending..._ placeholders
    13→ *
    14→ * BEHAVIOR:
    15→ * - Currently WARNS (logs to stderr) if validation fails
    16→ * - TODO: Can be upgraded to BLOCK response if validation fails
    17→ *
    18→ * CALLED BY: StopOrchestrator.hook.ts
    19→ */
    20→
    21→import { existsSync, readFileSync, statSync } from 'fs';
    22→import { join } from 'path';
    23→import type { ParsedTranscript } from '../../skills/PAI/Tools/TranscriptParser';
    24→
    25→interface CurrentWork {
    26→  session_id: string;
    27→  session_dir: string;
    28→  current_task: string;
    29→  task_count: number;
    30→  created_at: string;
    31→}
    32→
    33→interface ISCData {
    34→  taskId: string;
    35→  status: string;
    36→  effortLevel: string;
    37→  criteria: string[];
    38→  antiCriteria: string[];
    39→  satisfaction: Record<string, boolean> | null;
    40→  createdAt: string;
    41→  updatedAt: string;
    42→}
    43→
    44→interface ValidationResult {
    45→  valid: boolean;
    46→  warnings: string[];
    47→  errors: string[];
    48→}
    49→
    50→const BASE_DIR = process.env.PAI_DIR || join(process.env.HOME!, '.claude');
    51→const WORK_DIR = join(BASE_DIR, 'MEMORY', 'WORK');
    52→const STATE_DIR = join(BASE_DIR, 'MEMORY', 'STATE');
    53→const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    54→
    55→function readCurrentWork(): CurrentWork | null {
    56→  try {
    57→    if (!existsSync(CURRENT_WORK_FILE)) return null;
    58→    return JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
    59→  } catch {
    60→    return null;
    61→  }
    62→}
    63→
    64→function readISC(taskPath: string): ISCData | null {
    65→  try {
    66→    const iscPath = join(taskPath, 'ISC.json');
    67→    if (!existsSync(iscPath)) return null;
    68→    return JSON.parse(readFileSync(iscPath, 'utf-8'));
    69→  } catch {
    70→    return null;
    71→  }
    72→}
    73→
    74→function readThread(taskPath: string): string | null {
    75→  try {
    76→    const threadPath = join(taskPath, 'THREAD.md');
    77→    if (!existsSync(threadPath)) return null;
    78→    return readFileSync(threadPath, 'utf-8');
    79→  } catch {
    80→    return null;
    81→  }
    82→}
    83→
    84→function getFileModTime(filePath: string): Date | null {
    85→  try {
    86→    if (!existsSync(filePath)) return null;
    87→    const stats = statSync(filePath);
    88→    return stats.mtime;
    89→  } catch {
    90→    return null;
    91→  }
    92→}
    93→
    94→function validate(taskPath: string, currentWork: CurrentWork): ValidationResult {
    95→  const result: ValidationResult = {
    96→    valid: true,
    97→    warnings: [],
    98→    errors: [],
    99→  };
   100→
   101→  // Check ISC.json
   102→  const isc = readISC(taskPath);
   103→  if (!isc) {
   104→    result.errors.push('ISC.json not found or unreadable');
   105→    result.valid = false;
   106→    return result;
   107→  }
   108→
   109→  // Rule 1: Criteria array must be non-empty
   110→  if (!isc.criteria || isc.criteria.length === 0) {
   111→    result.warnings.push('ISC.json criteria array is EMPTY - algorithm may not have executed properly');
   112→  }
   113→
   114→  // Rule 2: Check if ISC.json was modified after session start
   115→  const iscPath = join(taskPath, 'ISC.json');
   116→  const iscModTime = getFileModTime(iscPath);
   117→  const sessionStart = new Date(currentWork.created_at);
   118→
   119→  if (iscModTime && iscModTime <= sessionStart) {
   120→    result.warnings.push('ISC.json not modified since session start - no updates during algorithm execution');
   121→  }
   122→
   123→  // Check THREAD.md
   124→  const thread = readThread(taskPath);
   125→  if (!thread) {
   126→    result.errors.push('THREAD.md not found or unreadable');
   127→    result.valid = false;
   128→    return result;
   129→  }
   130→
   131→  // Rule 3: Check for _Pending..._ placeholders
   132→  const pendingCount = (thread.match(/_Pending\.\.\._/g) || []).length;
   133→  if (pendingCount > 0) {
   134→    result.warnings.push(`THREAD.md has ${pendingCount} phases still marked _Pending..._ - algorithm phases not logged`);
   135→  }
   136→
   137→  return result;
   138→}
   139→
   140→export interface ISCValidationResult {
   141→  shouldBlock: boolean;
   142→  blockReason?: string;
   143→  warnings: string[];
   144→  errors: string[];
   145→}
   146→
   147→export async function handleISCValidation(
   148→  parsed: ParsedTranscript,
   149→  hookInput: { session_id: string }
   150→): Promise<ISCValidationResult> {
   151→  const result: ISCValidationResult = {
   152→    shouldBlock: false,
   153→    warnings: [],
   154→    errors: [],
   155→  };
   156→
   157→  const currentWork = readCurrentWork();
   158→  if (!currentWork) {
   159→    console.error('[ISCValidator] No current work found - skipping validation');
   160→    return result;
   161→  }
   162→
   163→  // Skip if session IDs don't match
   164→  if (currentWork.session_id !== hookInput.session_id) {
   165→    console.error('[ISCValidator] Session ID mismatch - skipping validation');
   166→    return result;
   167→  }
   168→
   169→  const taskPath = join(WORK_DIR, currentWork.session_dir, 'tasks', currentWork.current_task);
   170→  if (!existsSync(taskPath)) {
   171→    console.error(`[ISCValidator] Task path not found: ${taskPath}`);
   172→    return result;
   173→  }
   174→
   175→  const validationResult = validate(taskPath, currentWork);
   176→  result.warnings = validationResult.warnings;
   177→  result.errors = validationResult.errors;
   178→
   179→  // Log results
   180→  if (result.errors.length > 0) {
   181→    console.error('[ISCValidator] ERRORS:');
   182→    result.errors.forEach((e) => console.error(`  ❌ ${e}`));
   183→  }
   184→
   185→  if (result.warnings.length > 0) {
   186→    console.error('[ISCValidator] WARNINGS:');
   187→    result.warnings.forEach((w) => console.error(`  ⚠️  ${w}`));
   188→  }
   189→
   190→  // Check if OBSERVE phase was attempted (algorithm was run)
   191→  const responseText = parsed.plainCompletion || '';
   192→  const algorithmAttempted = responseText.includes('OBSERVE') ||
   193→                              responseText.includes('📦 CAPABILITIES') ||
   194→                              responseText.includes('ISC TRACKER');
   195→
   196→  // BLOCKING LOGIC: If algorithm was attempted but ISC is empty, block
   197→  const isc = readISC(taskPath);
   198→  if (algorithmAttempted && isc && (!isc.criteria || isc.criteria.length === 0)) {
   199→    result.shouldBlock = true;
   200→    result.blockReason = `ISC.json criteria array is EMPTY after algorithm execution.
   201→
   202→You attempted the algorithm but did not populate ISC criteria.
   203→
   204→REQUIRED:
   205→1. In OBSERVE phase, build 3-10 ISC criteria
   206→2. Write criteria to ISC.json before proceeding
   207→3. Each criterion: 8-12 words, binary testable STATE
   208→
   209→Example criterion: "Research agents return findings within two minutes"
   210→
   211→Fix the ISC.json and try again.`;
   212→  }
   213→
   214→  if (validationResult.valid && result.warnings.length === 0) {
   215→    console.error('[ISCValidator] ✓ All validation checks passed');
   216→  }
   217→
   218→  return result;
   219→}
