     1→/**
     2→ * Work Utilities
     3→ * Shared functions for working with WORK directories
     4→ */
     5→
     6→import { existsSync, readFileSync, readdirSync } from 'fs';
     7→import { join } from 'path';
     8→
     9→export type AlgorithmPhase = 'OBSERVE' | 'THINK' | 'PLAN' | 'BUILD' | 'EXECUTE' | 'VERIFY' | 'LEARN';
    10→
    11→const CLAUDE_DIR = process.env.PAI_DIR || process.env.HOME + '/.claude';
    12→const WORK_DIR = join(CLAUDE_DIR, 'MEMORY', 'WORK');
    13→
    14→/**
    15→ * Find the most recent active work directory
    16→ */
    17→export function findActiveWorkDir(): string | null {
    18→  try {
    19→    if (!existsSync(WORK_DIR)) return null;
    20→
    21→    const entries = readdirSync(WORK_DIR, { withFileTypes: true })
    22→      .filter(d => d.isDirectory() && d.name !== 'Signals')
    23→      .map(d => ({ name: d.name, path: join(WORK_DIR, d.name) }))
    24→      .sort((a, b) => b.name.localeCompare(a.name));
    25→
    26→    if (entries.length === 0) return null;
    27→
    28→    // Return most recent that isn't completed
    29→    for (const entry of entries) {
    30→      // Check session META.yaml for status
    31→      const metaPath = join(entry.path, 'META.yaml');
    32→      if (existsSync(metaPath)) {
    33→        const content = readFileSync(metaPath, 'utf-8');
    34→        if (!content.includes('status: "COMPLETED"')) {
    35→          return entry.path;
    36→        }
    37→      } else {
    38→        // No META.yaml means session is likely active (new format)
    39→        const tasksDir = join(entry.path, 'tasks');
    40→        if (existsSync(tasksDir)) {
    41→          return entry.path;
    42→        }
    43→      }
    44→    }
    45→
    46→    // Fallback to most recent
    47→    return entries[0].path;
    48→  } catch {
    49→    return null;
    50→  }
    51→}
    52→

