   285→function findWallpaper(query: string): string | null {
   286→  const wallpapers = getWallpapers();
   287→  const queryLower = query.toLowerCase();
   288→
   289→  // Exact match (without extension)
   290→  const exact = wallpapers.find((w) => getWallpaperName(w).toLowerCase() === queryLower);
   291→  if (exact) return exact;
   292→
   293→  // Partial match
   294→  const partial = wallpapers.find((w) => getWallpaperName(w).toLowerCase().includes(queryLower));
   295→  if (partial) return partial;
   296→
   297→  // Fuzzy: any word match
   298→  const words = queryLower.split(/[-_\s]+/);
   299→  const fuzzy = wallpapers.find((w) => {
   300→    const name = getWallpaperName(w).toLowerCase();
   301→    return words.some((word) => name.includes(word));
   302→  });
   303→  return fuzzy || null;
   304→}
