    73→
    74→import { execSync } from 'child_process';
    75→import { inference } from '../skills/PAI/Tools/Inference';
    76→import { isValidTabSummary, getTabFallback } from './lib/response-format';
    77→
    78→
    79→// Tab colors - different states
    80→const TAB_WORKING_BG = '#804000';      // Dark orange - actively working
    81→const TAB_INFERENCE_BG = '#1E0A3C';    // Very dark purple - inference/AI thinking
    82→const ACTIVE_TAB_BG = '#002B80';       // Dark blue - active tab base
    83→const ACTIVE_TEXT = '#FFFFFF';          // White text for active
    84→const INACTIVE_TEXT = '#A0A0A0';        // Gray text for inactive
    85→
    86→
    87→interface HookInput {
    88→  session_id: string;
    89→  prompt: string;
    90→  transcript_path: string;
    91→  hook_event_name: string;
    92→}
    93→
    94→/**
    95→ * Read stdin with timeout
    96→ */
    97→async function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
    98→  return new Promise((resolve, reject) => {
    99→    let data = '';
   100→    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
   101→    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
   102→    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
   103→    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
   104→  });
   105→}
