   194→    const minutes = Math.round((end.getTime() - start.getTime()) / 60000);
   195→    if (minutes < 60) {
   196→      duration = `${minutes} minutes`;
   197→    } else {
   198→      const hours = Math.floor(minutes / 60);
   199→      const mins = minutes % 60;
   200→      duration = `${hours}h ${mins}m`;
